            teacherId: inv.funds.teacher_id,
            unitPrice: inv.funds.unit_price,
            targetAmount: inv.funds.target_amount,
            baseReward: inv.funds.base_reward,
            incentiveReward: inv.funds.incentive_reward,
            recruitmentDeadline: inv.funds.recruitment_deadline,
            maturityDate: inv.funds.maturity_date,
        } : undefined
    }));
};


export const api = {
    login,
    loginWithPassword,
    changePassword,
    resetPassword,
    loginWithQrToken,
    getUsersByRole,
    addStudent,
    deleteStudents,
    getStudentAccountByUserId,
    getTeacherAccount,
    getTransactionsByAccountId,
    getRecipientDetailsByAccountId,
    transfer,
    studentWithdraw,
    bankerDeposit,
    bankerWithdraw,
    martTransfer,
    getStockProducts,
    getStudentStocks,
    getStockHistory,
    buyStock,
    sellStock,
    addStockProduct,
    updateStockPrice,
    updateStockVolatility,
    deleteStockProducts,
    getStockHolders,
    getSavingsProducts,
    getStudentSavings,
    joinSavings,
    cancelSavings,
    addSavingsProduct,
    deleteSavingsProducts,
    getSavingsEnrollees,
    getJobs,
    addJob,
    updateJob,
    deleteJob,
    deleteJobs,
    manageJobAssignment,
    updateJobIncentive,
    payJobSalary,
    payAllSalaries,
    getTaxes,
    createTax,
    deleteTax,
    getMyUnpaidTaxes,
    payTax,
    getFunds,
    createFund,
    joinFund,
    settleFund,
    getMyFundInvestments,
};

