const addStockProduct = async (name: string, price: number): Promise<string> => {
    // Revert to using the RPC as direct insert fails due to Foreign Key constraints (missing Account)
    // The RPC is expected to handle User and Account creation internally.
    const { data, error } = await supabase.rpc('add_stock_product', {
        p_name: name,
        p_initial_price: price
    });

    if (error) {
        // Special handling for RLS error
        if (error.code === '42501' || error.message.includes('permission denied') || error.message.includes('violates row-level security policy')) {
             throw new Error(
                "권한 오류(RLS)입니다. Supabase SQL Editor에서 다음을 실행하세요:\n\n" +
                "ALTER FUNCTION public.add_stock_product(text, integer) SECURITY DEFINER;"
             );
        }
        // Special handling for Ambiguous Function Error
        if (error.message.includes('Could not choose the best candidate function')) {
             throw new Error(
                "함수 중복 오류(Ambiguity)입니다. Supabase SQL Editor에서 아래 코드를 실행하여 중복된 함수를 제거하고 다시 생성해주세요:\n\n" +
                "DROP FUNCTION IF EXISTS public.add_stock_product(text, integer);\n" +
                "DROP FUNCTION IF EXISTS public.add_stock_product(text, numeric);\n\n" +
                `CREATE OR REPLACE FUNCTION public.add_stock_product(p_name text, p_initial_price integer)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $function$
DECLARE
    v_user_id uuid;
    v_account_id uuid;
BEGIN
    v_user_id := gen_random_uuid();
