    RETURN '새로운 주식 종목이 추가되었습니다.';
END;
$function$;`
             );
        }
        // Special handling for missing function error (42883)
        if (error.code === '42883' || (error.message.includes('function') && error.message.includes('does not exist'))) {
             throw new Error(
                "데이터베이스 함수가 없습니다. Supabase SQL Editor에서 다음 SQL을 실행하여 함수를 생성해주세요:\n\n" +
                `CREATE OR REPLACE FUNCTION public.add_stock_product(p_name text, p_initial_price integer)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $function$
DECLARE
    v_user_id uuid;
    v_account_id uuid;
BEGIN
    v_user_id := gen_random_uuid();
    INSERT INTO public.users ("userId", name, role) VALUES (v_user_id, p_name, 'stock');
    INSERT INTO public.accounts ("userId", balance) VALUES (v_user_id, 0) RETURNING id INTO v_account_id;
    INSERT INTO public.stock_products (name, "currentPrice", "stockAccountId") VALUES (p_name, p_initial_price, v_account_id);
    RETURN '새로운 주식 종목이 추가되었습니다.';
END;
$function$;`
             );
        }
        handleSupabaseError(error, 'addStockProduct');
    }
    return typeof data === 'string' ? data : '새로운 주식 종목이 추가되었습니다.';
};

