const addStockProduct = async (name: string, price: number): Promise<string> => {
    // Revert to using the RPC as direct insert fails due to Foreign Key constraints (missing Account)
    // The RPC is expected to handle User and Account creation internally.
    const { data, error } = await supabase.rpc('add_stock_product', {
        p_name: name,
        p_initial_price: price
    });

    if (error) {
        // Special handling for RLS error
        if (error.code === '42501' || error.message.includes('permission denied') || error.message.includes('violates row-level security policy')) {
             throw new Error(
                "권한 오류(RLS)입니다. Supabase SQL Editor에서 다음을 실행하세요:\n\n" +
                "ALTER FUNCTION public.add_stock_product(text, integer) SECURITY DEFINER;"
             );
        }
        // Special handling for Ambiguous Function Error
        if (error.message.includes('Could not choose the best candidate function')) {
             throw new Error(
                "함수 중복 오류(Ambiguity)입니다. Supabase SQL Editor에서 아래 코드를 실행하여 중복된 함수를 제거하고 다시 생성해주세요:\n\n" +
                "DROP FUNCTION IF EXISTS public.add_stock_product(text, integer);\n" +
                "DROP FUNCTION IF EXISTS public.add_stock_product(text, numeric);\n\n" +
                `CREATE OR REPLACE FUNCTION public.add_stock_product(p_name text, p_initial_price integer)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $function$
DECLARE
    v_user_id uuid;
    v_account_id uuid;
BEGIN
    v_user_id := gen_random_uuid();
    INSERT INTO public.users ("userId", name, role) VALUES (v_user_id, p_name, 'stock');
    INSERT INTO public.accounts ("userId", balance) VALUES (v_user_id, 0) RETURNING id INTO v_account_id;
    INSERT INTO public.stock_products (name, "currentPrice", "stockAccountId") VALUES (p_name, p_initial_price, v_account_id);
    RETURN '새로운 주식 종목이 추가되었습니다.';
END;
$function$;`
             );
        }
        // Special handling for 'column "id" does not exist' error
        if (error.message.includes('column "id" does not exist')) {
             throw new Error(
                "테이블 스키마 오류입니다. accounts 테이블에 'id' 컬럼이 없고 'accountId'를 사용하는 것으로 보입니다.\n" +
                "Supabase SQL Editor에서 아래 코드를 실행하여 함수를 업데이트해주세요:\n\n" +
                "DROP FUNCTION IF EXISTS public.add_stock_product(text, integer);\n" +
                "DROP FUNCTION IF EXISTS public.add_stock_product(text, numeric);\n\n" +
                `CREATE OR REPLACE FUNCTION public.add_stock_product(p_name text, p_initial_price integer)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $function$
DECLARE
    v_user_id uuid;
    v_account_id text; -- id 대신 accountId(text)를 받을 수 있도록 변경
BEGIN
    v_user_id := gen_random_uuid();
    INSERT INTO public.users ("userId", name, role) VALUES (v_user_id, p_name, 'stock');

    -- id 대신 accountId를 반환받습니다. (테이블에 id 컬럼이 없는 경우 대비)
    INSERT INTO public.accounts ("userId", balance) 
    VALUES (v_user_id, 0) 
    RETURNING "accountId" INTO v_account_id;

    INSERT INTO public.stock_products (name, "currentPrice", "stockAccountId") 
    VALUES (p_name, p_initial_price, v_account_id);

    RETURN '새로운 주식 종목이 추가되었습니다.';
END;
$function$;`
             );
        }

        // Special handling for missing function error (42883)
        if (error.code === '42883' || (error.message.includes('function') && error.message.includes('does not exist'))) {
             throw new Error(
                "데이터베이스 함수가 없습니다. Supabase SQL Editor에서 다음 SQL을 실행하여 함수를 생성해주세요:\n\n" +
                `CREATE OR REPLACE FUNCTION public.add_stock_product(p_name text, p_initial_price integer)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $function$
DECLARE
    v_user_id uuid;
    v_account_id uuid;
BEGIN
    v_user_id := gen_random_uuid();
    INSERT INTO public.users ("userId", name, role) VALUES (v_user_id, p_name, 'stock');
    INSERT INTO public.accounts ("userId", balance) VALUES (v_user_id, 0) RETURNING id INTO v_account_id;
    INSERT INTO public.stock_products (name, "currentPrice", "stockAccountId") VALUES (p_name, p_initial_price, v_account_id);
    RETURN '새로운 주식 종목이 추가되었습니다.';
END;
$function$;`
             );
        }
        handleSupabaseError(error, 'addStockProduct');
    }
    return typeof data === 'string' ? data : '새로운 주식 종목이 추가되었습니다.';
};

