### **2. Supabase SQL Editor 실행용 스크립트 (문제 해결용)**

아래 SQL 코드를 복사하여 **Supabase 대시보드 > SQL Editor**에서 실행하면 즉시 해결됩니다.

```sql
-- 기존 중복 함수 제거
DROP FUNCTION IF EXISTS public.add_stock_product(text, integer);
DROP FUNCTION IF EXISTS public.add_stock_product(text, numeric);

-- 올바른 함수 재생성 (id 대신 accountId 반환)
CREATE OR REPLACE FUNCTION public.add_stock_product(p_name text, p_initial_price integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_user_id uuid;
    v_account_id text; -- id 대신 accountId를 저장할 변수 (text)
BEGIN
    -- 1. 가상 유저 생성
    v_user_id := gen_random_uuid();
    INSERT INTO public.users ("userId", name, role) VALUES (v_user_id, p_name, 'stock');

    -- 2. 계좌 생성 후 accountId 반환 (id 컬럼이 없을 경우 대비)
    INSERT INTO public.accounts ("userId", balance) 
    VALUES (v_user_id, 0) 
    RETURNING "accountId" INTO v_account_id;

    -- 3. 주식 종목 생성 (stockAccountId에 텍스트 ID 저장)
    INSERT INTO public.stock_products (name, "currentPrice", "stockAccountId") 
    VALUES (p_name, p_initial_price, v_account_id);

    RETURN '새로운 주식 종목이 추가되었습니다.';
END;
$function$;

