### **2. Supabase SQL Editor 실행용 스크립트 (문제 해결용)**

아래 코드를 **Supabase SQL Editor**에 복사해 실행하세요. 이 스크립트는 기존의 문제 있는 함수를 **삭제(DROP)**하고, 필수 데이터(accountId)를 자동 생성하는 **올바른 버전(CREATE)**으로 교체합니다.

```sql
-- 1. 기존 함수 삭제 (중복 방지 및 클린업)
DROP FUNCTION IF EXISTS public.add_stock_product(text, integer);
DROP FUNCTION IF EXISTS public.add_stock_product(text, numeric);

-- 2. 개선된 함수 생성 (accountId 자동 생성 포함)
CREATE OR REPLACE FUNCTION public.add_stock_product(p_name text, p_initial_price integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_user_id uuid;
    v_account_number text;
BEGIN
    -- 가상 유저(주식 종목) 생성
    v_user_id := gen_random_uuid();
    INSERT INTO public.users ("userId", name, role) VALUES (v_user_id, p_name, 'stock');

    -- 필수 데이터인 accountId를 랜덤하게 생성 (예: 900-1234)
    -- '900-' 접두사는 주식 계좌임을 식별하기 위해 임의로 지정함
    v_account_number := '900-' || floor(random() * 8999 + 1000)::text;

    -- 계좌 생성 (필수 컬럼 accountId 포함)
    INSERT INTO public.accounts ("userId", balance, "accountId") 
    VALUES (v_user_id, 0, v_account_number);

    -- 주식 종목 생성 (생성된 계좌번호 연결)
    INSERT INTO public.stock_products (name, "currentPrice", "stockAccountId") 
    VALUES (p_name, p_initial_price, v_account_number);

    RETURN '새로운 주식 종목이 추가되었습니다.';
END;
$function$;

