### **2. Supabase SQL Script (문제 해결용)**

아래 코드를 복사하여 **Supabase 대시보드 > SQL Editor**에서 실행하면 즉시 해결됩니다.
이 스크립트는 `transfer_funds` 함수를 생성하고, 주식 매수/매도 로직을 보완하며, 적금 해지 로직을 추가합니다.

```sql
-- 1. transfer_funds 함수 생성 (송금 기능 오류 해결)
CREATE OR REPLACE FUNCTION public.transfer_funds(p_sender_user_id uuid, p_receiver_account_pk_id uuid, p_transfer_amount integer, p_memo text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_sender_account_id uuid;
    v_sender_balance integer;
    v_receiver_balance integer;
BEGIN
    -- 1. 보내는 사람의 계좌 확인
    SELECT id, balance INTO v_sender_account_id, v_sender_balance
    FROM public.accounts
    WHERE "userId" = p_sender_user_id
    LIMIT 1;

    IF v_sender_account_id IS NULL THEN
        RAISE EXCEPTION '보내는 사람의 계좌를 찾을 수 없습니다.';
    END IF;

    -- 2. 잔액 확인
    IF v_sender_balance < p_transfer_amount THEN
        RAISE EXCEPTION '잔액이 부족합니다.';
    END IF;

    -- 3. 받는 사람의 계좌 확인
    SELECT balance INTO v_receiver_balance
    FROM public.accounts
    WHERE id = p_receiver_account_pk_id;

    IF v_receiver_balance IS NULL THEN
        RAISE EXCEPTION '받는 사람의 계좌를 찾을 수 없습니다.';
    END IF;

    -- 4. 트랜잭션 수행 (송금)
    UPDATE public.accounts SET balance = balance - p_transfer_amount WHERE id = v_sender_account_id;
    UPDATE public.accounts SET balance = balance + p_transfer_amount WHERE id = p_receiver_account_pk_id;

    -- 5. 거래 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_sender_account_id, 'Transfer', -p_transfer_amount, p_memo || ' (보냄)');

    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (p_receiver_account_pk_id, 'Transfer', p_transfer_amount, p_memo || ' (받음)');

    RETURN json_build_object('success', true, 'message', '송금이 완료되었습니다.');
END;
$function$;


-- 2. buy_stock 함수 재정의 (주식 매수 오류 해결 - 계좌번호 매핑 강화)
CREATE OR REPLACE FUNCTION public.buy_stock(p_user_id uuid, p_stock_id uuid, p_quantity integer)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_account_id uuid;
    v_account_pk_id uuid; -- accounts table PK
    v_balance integer;
    v_stock_price integer;
    v_total_cost integer;
    v_stock_account_number text; -- stock_products table's stockAccountId (string)
    v_stock_account_pk_id uuid; -- accounts table PK for the stock market
BEGIN
    -- 1. 사용자 계좌 및 잔액 조회
    SELECT id, balance INTO v_account_pk_id, v_balance
    FROM public.accounts
    WHERE "userId" = p_user_id
    LIMIT 1;

    IF v_account_pk_id IS NULL THEN
        RAISE EXCEPTION '계좌를 찾을 수 없습니다.';
    END IF;

    -- 2. 주식 가격 및 주식 시장 계좌번호 조회
    SELECT "currentPrice", "stockAccountId" INTO v_stock_price, v_stock_account_number
    FROM public.stock_products
    WHERE id = p_stock_id;

    IF v_stock_price IS NULL THEN
        RAISE EXCEPTION '존재하지 않는 주식 종목입니다.';
    END IF;

    -- 3. 주식 시장의 실제 계좌 PK 조회
    SELECT id INTO v_stock_account_pk_id
    FROM public.accounts
    WHERE "accountId" = v_stock_account_number;

    -- 4. 비용 계산 및 잔액 확인
    v_total_cost := v_stock_price * p_quantity;

    IF v_balance < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다. (필요: %권, 보유: %권)', v_total_cost, v_balance;
    END IF;

    -- 5. 자금 이동 (학생 -> 주식시장)
    UPDATE public.accounts SET balance = balance - v_total_cost WHERE id = v_account_pk_id;

    -- 주식 시장 계좌가 존재하면 입금 처리 (없어도 에러 없이 진행, 보통 시스템 계좌는 없을 수도 있음)
    IF v_stock_account_pk_id IS NOT NULL THEN
        UPDATE public.accounts SET balance = balance + v_total_cost WHERE id = v_stock_account_pk_id;
    END IF;

    -- 6. 주식 보유량 업데이트 (INSERT or UPDATE)
    INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
    VALUES (p_user_id, p_stock_id, p_quantity, v_stock_price)
    ON CONFLICT ("userId", "stockId") 
    DO UPDATE SET 
        quantity = student_stocks.quantity + p_quantity,
        -- 평균 단가 계산 (간단화: 기존 총액 + 신규 총액 / 전체 수량)
        "purchasePrice" = ((student_stocks.quantity * student_stocks."purchasePrice") + (EXCLUDED.quantity * EXCLUDED."purchasePrice")) / (student_stocks.quantity + EXCLUDED.quantity);

    -- 7. 거래 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_account_pk_id, 'StockBuy', -v_total_cost, '주식 매수');
END;
$function$;


-- 3. sell_stock 함수 재정의 (주식 매도 오류 해결)
CREATE OR REPLACE FUNCTION public.sell_stock(p_user_id uuid, p_stock_id uuid, p_quantity integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_account_pk_id uuid;
    v_current_stock_quantity integer;
    v_stock_price integer;
    v_total_amount integer;
    v_stock_name text;
    v_volatility numeric;
    v_fee_rate numeric;
    v_fee integer;
    v_final_amount integer;
    v_stock_account_number text;
    v_stock_account_pk_id uuid;
BEGIN
    -- 1. 사용자 계좌 조회
    SELECT id INTO v_account_pk_id
    FROM public.accounts
    WHERE "userId" = p_user_id
    LIMIT 1;

    -- 2. 보유 주식 확인
    SELECT quantity INTO v_current_stock_quantity
    FROM public.student_stocks
    WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

    IF v_current_stock_quantity IS NULL OR v_current_stock_quantity < p_quantity THEN
        RAISE EXCEPTION '보유 주식 수량이 부족합니다.';
    END IF;

    -- 3. 주식 정보 조회 (가격, 민감도, 이름)
    SELECT "currentPrice", volatility, name, "stockAccountId" INTO v_stock_price, v_volatility, v_stock_name, v_stock_account_number
    FROM public.stock_products
    WHERE id = p_stock_id;

    -- 주식 시장 계좌 PK 조회
    SELECT id INTO v_stock_account_pk_id FROM public.accounts WHERE "accountId" = v_stock_account_number;

    -- 4. 판매 금액 및 수수료 계산
    v_total_amount := v_stock_price * p_quantity;

    -- 수수료 계산 공식: F = 10k / (1 + 10k), 기본값 k=0.01 -> 약 0.9%
    IF v_volatility IS NULL THEN v_volatility := 0.01; END IF;
    v_fee_rate := (10 * v_volatility) / (1 + 10 * v_volatility);
    v_fee := floor(v_total_amount * v_fee_rate);
    v_final_amount := v_total_amount - v_fee;

    -- 5. 자금 이동 (주식시장 -> 학생)
    UPDATE public.accounts SET balance = balance + v_final_amount WHERE id = v_account_pk_id;

    IF v_stock_account_pk_id IS NOT NULL THEN
        UPDATE public.accounts SET balance = balance - v_final_amount WHERE id = v_stock_account_pk_id;
    END IF;

    -- 6. 보유 주식 감소
    IF v_current_stock_quantity = p_quantity THEN
        DELETE FROM public.student_stocks WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    ELSE
        UPDATE public.student_stocks SET quantity = quantity - p_quantity WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    END IF;

    -- 7. 거래 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_account_pk_id, 'StockSell', v_final_amount, '주식 매도 (' || v_stock_name || ') - 수수료 ' || v_fee || '권 차감');

    RETURN '주식 매도 완료';
END;
$function$;


-- 4. cancel_savings 함수 정의 (적금 해지 오류 해결)
CREATE OR REPLACE FUNCTION public.cancel_savings(p_user_id uuid, p_saving_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_account_pk_id uuid;
    v_saving_amount integer;
    v_cancellation_rate numeric;
    v_refund_amount integer;
    v_product_name text;
BEGIN
    -- 1. 사용자 계좌 조회
    SELECT id INTO v_account_pk_id
    FROM public.accounts
    WHERE "userId" = p_user_id
    LIMIT 1;

    -- 2. 적금 정보 조회
    SELECT ss.amount, sp.name, sp."cancellationRate"
    INTO v_saving_amount, v_product_name, v_cancellation_rate
    FROM public.student_savings ss
    JOIN public.savings_products sp ON ss."productId" = sp.id
    WHERE ss."savingId" = p_saving_id AND ss."userId" = p_user_id;

    IF v_saving_amount IS NULL THEN
        RAISE EXCEPTION '해당 적금 정보를 찾을 수 없습니다.';
    END IF;

    -- 3. 환급액 계산 (원금 * (1 - 해지수수료율))
    v_refund_amount := floor(v_saving_amount * (1 - v_cancellation_rate));

    -- 4. 자금 환급
    UPDATE public.accounts SET balance = balance + v_refund_amount WHERE id = v_account_pk_id;

    -- 5. 적금 삭제
    DELETE FROM public.student_savings WHERE "savingId" = p_saving_id;

    -- 6. 거래 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_account_pk_id, 'SavingsCancel', v_refund_amount, '적금 중도 해지 (' || v_product_name || ')');
END;
$function$;

