                message={`'${taxToPay?.name}' 세금 ${taxToPay?.amount.toLocaleString()}권을 납부하시겠습니까?`}
                onConfirm={handleConfirmPayment}
                onCancel={() => setTaxToPay(null)}
                confirmText="납부하기"
            />
        </div>
    );
};


