**문제 원인 분석:**
`42703` 오류("column 'id' does not exist")는 SQL 함수(`transfer_funds`)가 `public.accounts` 테이블에서 **`id`라는 이름의 컬럼을 조회하거나 사용하려고 했지만, 실제 데이터베이스 테이블에는 해당 컬럼이 없기 때문에 발생**합니다.

현재 사용 중인 `accounts` 테이블은 내부적으로 `id` (UUID) 컬럼 대신 `userId`나 `accountId`를 고유 키로 사용하고 있을 가능성이 높습니다. 따라서 **SQL 함수가 `id` 컬럼을 전혀 사용하지 않고, 확실하게 존재하는 `accountId`(계좌번호 문자열)와 `userId`만을 사용하도록 수정**해야 합니다.

아래 해결 방법을 순서대로 적용해주세요.

### **1. Supabase SQL Script (즉시 해결)**

이 스크립트는 `id` 컬럼에 대한 의존성을 완전히 제거하고, **계좌번호(문자열)와 사용자ID(텍스트)** 만을 사용하여 송금을 처리하도록 재작성되었습니다.
Supabase 대시보드 > SQL Editor에서 실행하세요.

```sql
-- 1. 기존 충돌 가능성 있는 함수들 삭제
DROP FUNCTION IF EXISTS public.transfer_funds(text, text, integer, text);
DROP FUNCTION IF EXISTS public.transfer_funds(uuid, text, integer, text);

-- 2. id 컬럼을 사용하지 않는 안전한 버전의 함수 생성
CREATE OR REPLACE FUNCTION public.transfer_funds(
    p_sender_user_id text,          -- 보내는 사람 ID (예: 'student-xxx')
    p_receiver_account_number text, -- 받는 사람 계좌번호 (예: '900-1234')
    p_transfer_amount integer,      -- 금액
    p_memo text                     -- 메모
)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_sender_account_number text;
    v_sender_balance integer;
    v_receiver_account_number text;
BEGIN
    -- 1. 보내는 사람 정보 조회 (id 컬럼 대신 userId 사용, 타입 캐스팅으로 안전성 확보)
    SELECT "accountId", balance INTO v_sender_account_number, v_sender_balance
    FROM public.accounts
    WHERE "userId"::text = p_sender_user_id
    LIMIT 1;

    IF v_sender_account_number IS NULL THEN
        RAISE EXCEPTION '보내는 사람의 계좌를 찾을 수 없습니다. (ID: %)', p_sender_user_id;
    END IF;

    -- 2. 잔액 확인
    IF v_sender_balance < p_transfer_amount THEN
        RAISE EXCEPTION '잔액이 부족합니다.';
    END IF;

    -- 3. 받는 사람 정보 조회 (계좌번호로 조회)
    SELECT "accountId" INTO v_receiver_account_number
    FROM public.accounts
    WHERE "accountId" = p_receiver_account_number
    LIMIT 1;

    IF v_receiver_account_number IS NULL THEN
        RAISE EXCEPTION '받는 사람의 계좌(%s)를 찾을 수 없습니다.', p_receiver_account_number;
    END IF;

    -- 4. 송금 실행 (UPDATE 시에도 id 대신 userId, accountId 사용)
    -- 보내는 사람 차감
    UPDATE public.accounts 
    SET balance = balance - p_transfer_amount 
    WHERE "userId"::text = p_sender_user_id;

    -- 받는 사람 입금
    UPDATE public.accounts 
    SET balance = balance + p_transfer_amount 
    WHERE "accountId" = v_receiver_account_number;

    -- 5. 거래 내역 기록 (id 대신 문자열 계좌번호 사용)
    -- transactions 테이블의 accountId 컬럼이 문자열이라고 가정
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_sender_account_number, 'Transfer', -p_transfer_amount, p_memo || ' (보냄)');

    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_receiver_account_number, 'Transfer', p_transfer_amount, p_memo || ' (받음)');

    RETURN json_build_object('success', true, 'message', '송금이 완료되었습니다.');
END;
$function$;
```

