const getStockProducts = async (): Promise<StockProductWithDetails[]> => {
    // 1. Fetch raw table data (Source of Truth)
    const { data: tableData, error: tableError } = await supabase
        .from('stock_products')
        .select('id, name, currentPrice, volatility');

    if (tableError) {
        console.error("Table Fetch Error:", tableError);
        throw new Error(tableError.message);
    }

    // 2. Fetch RPC data for calculated fields (valuation, quantity)
    const { data: rpcData, error: rpcError } = await supabase.rpc('get_stock_products_with_details');
    if (rpcError) {
        console.warn("RPC Error (non-critical):", rpcError);
        // We continue even if RPC fails, to show the stock list
    }

    // 3. Merge: Use table data as base, enhance with RPC data if available
    const mergedData = (tableData || []).map((tableItem: any) => {
        const rpcItem = (rpcData || []).find((r: any) => r.id === tableItem.id);
        return {
            id: tableItem.id,
            name: tableItem.name,
            currentPrice: tableItem.currentPrice, // Using Table's currentPrice as master
            volatility: tableItem.volatility || 0.01,
            stockAccountId: rpcItem?.stockAccountId || '', // Might be missing if RPC failed or new stock
            totalQuantity: rpcItem?.totalQuantity || 0,
            valuation: rpcItem?.valuation || 0
        };
    });

    return mergedData;
};

