네, 말씀하신 대로 **대소문자 구분(`"accountId"`, `"userId"`)**을 엄격하게 적용하여 수정한 SQL 쿼리입니다.

이 코드를 Supabase SQL Editor에 그대로 붙여넣고 실행(Run)하시면 해결됩니다.

```sql
-- 1. 기존 함수 삭제 (충돌 방지)
DROP FUNCTION IF EXISTS public.transfer_funds(text, text, integer, text);

-- 2. 대소문자 구분("columnName")을 적용한 함수 생성
CREATE OR REPLACE FUNCTION public.transfer_funds(
    p_sender_user_id text,          
    p_receiver_account_number text, 
    p_transfer_amount integer,      
    p_memo text                     
)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_sender_account_id text;
    v_sender_balance numeric; 
    v_receiver_account_id text;
BEGIN
    -- 1. 보내는 사람 정보 조회 
    -- "userId", "accountId" 컬럼명에 쌍따옴표 적용
    SELECT "accountId", balance INTO v_sender_account_id, v_sender_balance
    FROM public.accounts
    WHERE "userId" = p_sender_user_id
    LIMIT 1;

    IF v_sender_account_id IS NULL THEN
        RAISE EXCEPTION '보내는 사람의 계좌를 찾을 수 없습니다. (ID: %)', p_sender_user_id;
    END IF;

    -- 2. 잔액 확인
    IF v_sender_balance < p_transfer_amount THEN
        RAISE EXCEPTION '잔액이 부족합니다.';
    END IF;

    -- 3. 받는 사람 정보 조회
    -- "accountId" 컬럼명에 쌍따옴표 적용
    SELECT "accountId" INTO v_receiver_account_id
    FROM public.accounts
    WHERE "accountId" = p_receiver_account_number
    LIMIT 1;

    IF v_receiver_account_id IS NULL THEN
        RAISE EXCEPTION '받는 사람의 계좌(%s)를 찾을 수 없습니다.', p_receiver_account_number;
    END IF;

    -- 4. 송금 실행 (UPDATE)

    -- 보내는 사람 차감
    UPDATE public.accounts 
    SET balance = balance - p_transfer_amount 
    WHERE "userId" = p_sender_user_id;

    -- 받는 사람 입금
    UPDATE public.accounts 
    SET balance = balance + p_transfer_amount 
    WHERE "accountId" = v_receiver_account_id;

    -- 5. 거래 내역 기록 (INSERT)
    -- transactions 테이블의 컬럼도 대소문자가 구분된다면 "accountId"로 감싸야 합니다.
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_sender_account_id, 'Transfer', -p_transfer_amount, p_memo || ' (보냄)');

    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_receiver_account_id, 'Transfer', p_transfer_amount, p_memo || ' (받음)');

    RETURN json_build_object('success', true, 'message', '송금이 완료되었습니다.');
END;
$function$;

주식 매도/매수 기능에서 발생하는 `PGRST203` 에러는 **데이터베이스에 이름이 같고 매개변수 타입만 다른 두 개의 함수(`buy_stock`)가 동시에 존재하여** Supabase가 어떤 것을 실행해야 할지 혼란스러워하기 때문에 발생합니다. (하나는 입력값을 `text`로 받고, 다른 하나는 `uuid`로 받는 것으로 보입니다.)

가장 정확한 해결을 위해 다음 **3가지 정보**를 알려주시면, 불필요한 함수를 제거하고 딱 맞는 함수 하나만 남기는 SQL을 작성해 드릴 수 있습니다.

### 📋 제공해주셔야 할 정보 목록

1.  **`stock_products` 테이블의 `id` 컬럼 데이터 타입**
    *   (예: `uuid` 인지 `text` 인지)
2.  **`users` 테이블의 `userId` 컬럼 데이터 타입**
    *   (예: `text` 가 확실한지)
3.  **`student_stocks` 테이블의 구조**
    *   `stock_id` 컬럼의 타입 (`uuid` vs `text`)
    *   `user_id` 컬럼의 타입 (`text` 등)

---

### 💡 (참고) 정보 제공 없이 바로 해결을 시도하려면?

만약 정보를 확인하기 번거로우시다면, 아래 SQL 스크립트는 **"사용자 ID는 Text, 주식 ID도 Text(또는 UUID 호환)"**라고 가정하고, 중복된 함수를 모두 삭제한 뒤 새로 생성하는 명령어입니다. 

Supabase SQL Editor에서 실행하시면 문제가 해결될 가능성이 높습니다.

```sql
-- 1. 중복된 함수 모두 삭제 (오버로딩 충돌 방지)
DROP FUNCTION IF EXISTS public.buy_stock(text, text, integer);
DROP FUNCTION IF EXISTS public.buy_stock(uuid, uuid, integer);
DROP FUNCTION IF EXISTS public.buy_stock(text, uuid, integer);

DROP FUNCTION IF EXISTS public.sell_stock(text, text, integer);
DROP FUNCTION IF EXISTS public.sell_stock(uuid, uuid, integer);
DROP FUNCTION IF EXISTS public.sell_stock(text, uuid, integer);

-- 2. buy_stock 함수 재정의 (Text 타입 기준, 내부에서 필요시 uuid 캐스팅)
CREATE OR REPLACE FUNCTION public.buy_stock(
    p_user_id text,
    p_stock_id text,  -- UUID일 수도 있으므로 일단 text로 받고 내부에서 처리
    p_quantity integer
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_stock_price numeric;
    v_total_cost numeric;
    v_user_balance numeric;
    v_user_account_id text;
    v_current_qty integer;
    -- 실제 테이블 타입에 맞춰 변환할 변수
    v_real_stock_id text; -- 만약 DB가 uuid라면 이 부분 수정 필요 (아래 참조)
BEGIN
    -- [중요] 만약 stock_products.id가 UUID라면 아래 주석 해제 후 사용
    -- v_real_stock_id := p_stock_id::uuid;
    -- 현재는 Text로 가정
    v_real_stock_id := p_stock_id;

    -- 1. 주식 가격 확인
    SELECT "currentPrice" INTO v_stock_price
    FROM public.stock_products
    WHERE id = v_real_stock_id; -- 타입 불일치 시 ::uuid 캐스팅 필요할 수 있음

    IF v_stock_price IS NULL THEN
        RAISE EXCEPTION '존재하지 않는 주식입니다.';
    END IF;

    v_total_cost := v_stock_price * p_quantity;

    -- 2. 사용자 계좌 및 잔액 확인 ("userId" 컬럼 사용)
    SELECT "accountId", balance INTO v_user_account_id, v_user_balance
    FROM public.accounts
    WHERE "userId" = p_user_id;

    IF v_user_account_id IS NULL THEN
        RAISE EXCEPTION '계좌를 찾을 수 없습니다.';
    END IF;

    IF v_user_balance < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다. (필요: %권, 보유: %권)', v_total_cost, v_user_balance;
    END IF;

    -- 3. 거래 실행
    -- 현금 차감
    UPDATE public.accounts
    SET balance = balance - v_total_cost
    WHERE "accountId" = v_user_account_id;

    -- 주식 보유량 확인
    SELECT quantity INTO v_current_qty
    FROM public.student_stocks
    WHERE "userId" = p_user_id AND "stockId" = v_real_stock_id; -- stockId 대소문자 주의

    IF v_current_qty IS NULL THEN
        INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
        VALUES (p_user_id, v_real_stock_id, p_quantity, v_stock_price);
    ELSE
        UPDATE public.student_stocks
        SET quantity = quantity + p_quantity,
            "purchasePrice" = (("purchasePrice" * v_current_qty) + v_total_cost) / (v_current_qty + p_quantity)
        WHERE "userId" = p_user_id AND "stockId" = v_real_stock_id;
    END IF;

    -- 거래 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_user_account_id, 'StockBuy', -v_total_cost, '주식 매수: ' || p_quantity || '주');

    RETURN json_build_object('success', true, 'message', '주식 매수 성공');
END;
$$;

-- 3. sell_stock 함수 재정의
CREATE OR REPLACE FUNCTION public.sell_stock(
    p_user_id text,
    p_stock_id text,
    p_quantity integer
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_stock_price numeric;
    v_total_earn numeric;
    v_user_account_id text;
    v_current_qty integer;
    v_real_stock_id text;
BEGIN
    v_real_stock_id := p_stock_id;

    -- 1. 보유 주식 확인
    SELECT quantity INTO v_current_qty
    FROM public.student_stocks
    WHERE "userId" = p_user_id AND "stockId" = v_real_stock_id;

    IF v_current_qty IS NULL OR v_current_qty < p_quantity THEN
        RAISE EXCEPTION '보유 주식이 부족합니다.';
    END IF;

    -- 2. 현재가 확인
    SELECT "currentPrice" INTO v_stock_price
    FROM public.stock_products
    WHERE id = v_real_stock_id;

    v_total_earn := v_stock_price * p_quantity;

    -- 3. 계좌 확인
    SELECT "accountId" INTO v_user_account_id
    FROM public.accounts
    WHERE "userId" = p_user_id;

    -- 4. 거래 실행
    -- 주식 차감
    IF v_current_qty = p_quantity THEN
        DELETE FROM public.student_stocks
        WHERE "userId" = p_user_id AND "stockId" = v_real_stock_id;
    ELSE
        UPDATE public.student_stocks
        SET quantity = quantity - p_quantity
        WHERE "userId" = p_user_id AND "stockId" = v_real_stock_id;
    END IF;

    -- 현금 입금
    UPDATE public.accounts
    SET balance = balance + v_total_earn
    WHERE "accountId" = v_user_account_id;

    -- 거래 내역
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_user_account_id, 'StockSell', v_total_earn, '주식 매도: ' || p_quantity || '주');

    RETURN json_build_object('success', true, 'message', '주식 매도 성공');
END;
$$;

제공해주신 테이블 스키마 정보(`stock_products.id`는 text, `users.userId`는 text, `student_stocks.userId/stockId`는 text)를 바탕으로, **데이터 타입 충돌(PGRST203)** 문제를 해결하고 **대소문자 구분**까지 완벽하게 반영한 SQL 쿼리입니다.

현재 데이터베이스에 `uuid` 버전을 사용하는 `buy_stock` 함수와 `text` 버전을 사용하는 함수가 혼재되어 있어 오류가 발생하고 있습니다. 아래 스크립트는 **모든 중복 함수를 제거하고, Text 타입에 맞는 정확한 함수 하나만 생성**합니다.

이 코드를 Supabase SQL Editor에서 실행하시면 주식 매수/매도 기능이 정상 작동합니다.

```sql
-- 1. 중복된 함수 모두 삭제 (오버로딩 충돌 해결)
DROP FUNCTION IF EXISTS public.buy_stock(text, text, integer);
DROP FUNCTION IF EXISTS public.buy_stock(uuid, uuid, integer);
DROP FUNCTION IF EXISTS public.buy_stock(text, uuid, integer);

DROP FUNCTION IF EXISTS public.sell_stock(text, text, integer);
DROP FUNCTION IF EXISTS public.sell_stock(uuid, uuid, integer);
DROP FUNCTION IF EXISTS public.sell_stock(text, uuid, integer);

-- 2. buy_stock 함수 재정의 (Text ID 사용)
CREATE OR REPLACE FUNCTION public.buy_stock(
    p_user_id text,
    p_stock_id text,
    p_quantity integer
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_stock_price numeric;
    v_total_cost numeric;
    v_user_balance numeric;
    v_user_account_id text;
    v_current_qty integer;
BEGIN
    -- 1. 주식 가격 확인 (id 컬럼이 text이므로 그대로 비교)
    SELECT "currentPrice" INTO v_stock_price
    FROM public.stock_products
    WHERE id = p_stock_id;

    IF v_stock_price IS NULL THEN
        RAISE EXCEPTION '존재하지 않는 주식입니다. (ID: %)', p_stock_id;
    END IF;

    v_total_cost := v_stock_price * p_quantity;

    -- 2. 사용자 계좌 및 잔액 확인 ("userId" 대소문자 주의)
    SELECT "accountId", balance INTO v_user_account_id, v_user_balance
    FROM public.accounts
    WHERE "userId" = p_user_id;

    IF v_user_account_id IS NULL THEN
        RAISE EXCEPTION '계좌를 찾을 수 없습니다.';
    END IF;

    IF v_user_balance < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다. (필요: %권, 보유: %권)', v_total_cost, v_user_balance;
    END IF;

    -- 3. 거래 실행
    -- 현금 차감
    UPDATE public.accounts
    SET balance = balance - v_total_cost
    WHERE "accountId" = v_user_account_id;

    -- 주식 보유량 확인 ("userId", "stockId" 대소문자 주의)
    SELECT quantity INTO v_current_qty
    FROM public.student_stocks
    WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

    IF v_current_qty IS NULL THEN
        -- 신규 매수
        INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
        VALUES (p_user_id, p_stock_id, p_quantity, v_stock_price);
    ELSE
        -- 추가 매수 (평단가 갱신)
        UPDATE public.student_stocks
        SET quantity = quantity + p_quantity,
            "purchasePrice" = (("purchasePrice" * v_current_qty) + v_total_cost) / (v_current_qty + p_quantity)
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    END IF;

    -- 거래 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_user_account_id, 'StockBuy', -v_total_cost, '주식 매수: ' || p_quantity || '주');

    RETURN json_build_object('success', true, 'message', '주식 매수 성공');
END;
$$;

-- 3. sell_stock 함수 재정의 (Text ID 사용)
CREATE OR REPLACE FUNCTION public.sell_stock(
    p_user_id text,
    p_stock_id text,
    p_quantity integer
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_stock_price numeric;
    v_total_earn numeric;
    v_user_account_id text;
    v_current_qty integer;
BEGIN
    -- 1. 보유 주식 확인
    SELECT quantity INTO v_current_qty
    FROM public.student_stocks
    WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

    IF v_current_qty IS NULL OR v_current_qty < p_quantity THEN
        RAISE EXCEPTION '보유 주식이 부족합니다.';
    END IF;

    -- 2. 현재가 확인
    SELECT "currentPrice" INTO v_stock_price
    FROM public.stock_products
    WHERE id = p_stock_id;

    v_total_earn := v_stock_price * p_quantity;

    -- 3. 계좌 확인
    SELECT "accountId" INTO v_user_account_id
    FROM public.accounts
    WHERE "userId" = p_user_id;

    -- 4. 거래 실행
    -- 주식 차감
    IF v_current_qty = p_quantity THEN
        DELETE FROM public.student_stocks
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
