        UPDATE public.student_stocks
        SET quantity = quantity - p_quantity
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    END IF;

    -- 현금 입금
    UPDATE public.accounts
    SET balance = balance + v_total_earn
    WHERE "accountId" = v_user_account_id;

    -- 거래 내역
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_user_account_id, 'StockSell', v_total_earn, '주식 매도: ' || p_quantity || '주');

    RETURN json_build_object('success', true, 'message', '주식 매도 성공');
END;
