---

### 3. [중요] SQL 업데이트 (Supabase에서 실행)

아래 SQL을 **Supabase SQL Editor**에 붙여넣고 실행(Run)하여 주식 거래 로직을 업데이트해주세요. 이 로직이 있어야 **가격 변동**과 **수수료**가 정상적으로 작동합니다.

```sql
-- 기존 함수 삭제
DROP FUNCTION IF EXISTS public.buy_stock(text, text, integer);
DROP FUNCTION IF EXISTS public.sell_stock(text, text, integer);

-- 1. 매수 함수 (가격 상승 로직 포함)
CREATE OR REPLACE FUNCTION public.buy_stock(
    p_user_id text,
    p_stock_id text,
    p_quantity integer
)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_stock_price numeric;
    v_volatility numeric;
    v_total_cost numeric;
    v_user_balance numeric;
    v_user_account_id text;
    v_current_qty integer;
    v_new_price numeric;
BEGIN
    -- 1. 주식 정보 확인
    SELECT "currentPrice", volatility INTO v_stock_price, v_volatility
    FROM public.stock_products
    WHERE id = p_stock_id;

    IF v_stock_price IS NULL THEN
        RAISE EXCEPTION '존재하지 않는 주식입니다.';
    END IF;

    v_total_cost := v_stock_price * p_quantity;

    -- 2. 잔액 확인
    SELECT "accountId", balance INTO v_user_account_id, v_user_balance
    FROM public.accounts
    WHERE "userId" = p_user_id;

    IF v_user_balance < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다.';
    END IF;

    -- 3. 거래 실행: 현금 차감
    UPDATE public.accounts
    SET balance = balance - v_total_cost
    WHERE "accountId" = v_user_account_id;

    -- 4. 거래 실행: 주식 지급
    SELECT quantity INTO v_current_qty
    FROM public.student_stocks
    WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

    IF v_current_qty IS NULL THEN
        INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
        VALUES (p_user_id, p_stock_id, p_quantity, v_stock_price);
    ELSE
        UPDATE public.student_stocks
        SET quantity = quantity + p_quantity,
            "purchasePrice" = (("purchasePrice" * v_current_qty) + v_total_cost) / (v_current_qty + p_quantity)
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    END IF;

    -- 5. 가격 변동 (매수 시 상승)
    -- 공식: 현재가 * (1 + (민감도 * 수량 / 100))
    v_new_price := floor(v_stock_price * (1 + (coalesce(v_volatility, 0.01) * p_quantity * 0.01)));

    UPDATE public.stock_products
    SET "currentPrice" = v_new_price
    WHERE id = p_stock_id;

    INSERT INTO public.stock_price_history ("stockId", price)
    VALUES (p_stock_id, v_new_price);

    -- 6. 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_user_account_id, 'StockBuy', -v_total_cost, '주식 매수: ' || p_quantity || '주');

    RETURN '매수되었습니다.';
END;
$$;


-- 2. 매도 함수 (가격 하락 및 수수료 로직 포함)
CREATE OR REPLACE FUNCTION public.sell_stock(
    p_user_id text,
    p_stock_id text,
    p_quantity integer
)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_stock_price numeric;
    v_volatility numeric;
    v_total_earn numeric;
    v_fee numeric;
    v_final_earn numeric;
    v_user_account_id text;
    v_current_qty integer;
    v_new_price numeric;
BEGIN
    -- 1. 보유 주식 확인
    SELECT quantity INTO v_current_qty
    FROM public.student_stocks
    WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

    IF v_current_qty IS NULL OR v_current_qty < p_quantity THEN
        RAISE EXCEPTION '보유 주식이 부족합니다.';
    END IF;

    -- 2. 주식 정보 확인
    SELECT "currentPrice", volatility INTO v_stock_price, v_volatility
    FROM public.stock_products
    WHERE id = p_stock_id;

    -- 3. 수수료 및 정산금 계산
    -- 수수료율 = 민감도 (예: 0.01 = 1%)
    v_total_earn := v_stock_price * p_quantity;
    v_fee := floor(v_total_earn * coalesce(v_volatility, 0.01)); 
    v_final_earn := v_total_earn - v_fee;

    -- 4. 계좌 확인
    SELECT "accountId" INTO v_user_account_id
    FROM public.accounts
    WHERE "userId" = p_user_id;

    -- 5. 거래 실행: 주식 차감
    IF v_current_qty = p_quantity THEN
        DELETE FROM public.student_stocks
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    ELSE
        UPDATE public.student_stocks
        SET quantity = quantity - p_quantity
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    END IF;

    -- 6. 거래 실행: 현금 입금
    UPDATE public.accounts
    SET balance = balance + v_final_earn
    WHERE "accountId" = v_user_account_id;

    -- 7. 가격 변동 (매도 시 하락)
    -- 공식: 현재가 * (1 - (민감도 * 수량 / 100))
    v_new_price := floor(v_stock_price * (1 - (coalesce(v_volatility, 0.01) * p_quantity * 0.01)));

    -- 가격이 1원 미만으로 떨어지지 않도록 방지
    IF v_new_price < 1 THEN v_new_price := 1; END IF;

    UPDATE public.stock_products
    SET "currentPrice" = v_new_price
    WHERE id = p_stock_id;

    INSERT INTO public.stock_price_history ("stockId", price)
    VALUES (p_stock_id, v_new_price);

    -- 8. 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_user_account_id, 'StockSell', v_final_earn, '주식 매도: ' || p_quantity || '주 (수수료 ' || v_fee || '권 차감)');

    RETURN '매도되었습니다. (수수료: ' || v_fee || '권)';
END;
$$;

