네, 알겠습니다. **Supabase SQL Editor**에 바로 복사해서 붙여넣으실 수 있는 **전체 쿼리문**을 텍스트로 드립니다.

이 쿼리는 다음 기능을 포함합니다:
1.  **매수 함수 (`buy_stock`)**:
    *   **1회 10주 제한**, **총 보유 50주 제한** 적용.
    *   가격 상승: `현재가 * (1 + (민감도 * 수량))` (1주만 사도 민감도 %만큼 즉시 상승).
2.  **매도 함수 (`sell_stock`)**:
    *   **자가 증식 방지 수수료 ($F_{min} = \frac{10k}{2+10k}$)** 적용.
    *   가격 하락: `현재가 * (1 - (민감도 * 수량))` (매수와 동일 비율로 하락).

아래 내용을 복사해서 **Run** 하시면 됩니다.

```sql
-- 1. 매수 함수 (거래 제한 및 민감도 기반 가격 상승 적용)
CREATE OR REPLACE FUNCTION public.buy_stock(p_user_id text, p_stock_id text, p_quantity integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_stock_price numeric;
    v_volatility numeric;
    v_total_cost numeric;
    v_user_balance numeric;
    v_user_account_id text;
    v_my_current_qty integer;
    v_new_price numeric;
BEGIN
    -- [제한 1] 1회 거래 수량 제한 (10주)
    IF p_quantity > 10 THEN
        RAISE EXCEPTION '한 번에 최대 10주까지만 거래할 수 있습니다.';
    END IF;

    -- 1. 주식 정보 확인
    SELECT "currentPrice", volatility INTO v_stock_price, v_volatility
    FROM public.stock_products
    WHERE id = p_stock_id;

    IF v_stock_price IS NULL THEN
        RAISE EXCEPTION '존재하지 않는 주식입니다.';
    END IF;

    -- [제한 2] 총 보유 한도 확인 (50주)
    SELECT coalesce(quantity, 0) INTO v_my_current_qty
    FROM public.student_stocks
    WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

    IF (coalesce(v_my_current_qty, 0) + p_quantity) > 50 THEN
        RAISE EXCEPTION '한 종목당 최대 50주까지만 보유할 수 있습니다. (현재: %주)', coalesce(v_my_current_qty, 0);
    END IF;

    v_total_cost := v_stock_price * p_quantity;

    -- 2. 잔액 확인
    SELECT "accountId", balance INTO v_user_account_id, v_user_balance
    FROM public.accounts
    WHERE "userId" = p_user_id;

    IF v_user_balance < v_total_cost THEN
        RAISE EXCEPTION '잔액이 부족합니다.';
    END IF;

    -- 3. 거래 실행: 현금 차감
    UPDATE public.accounts
    SET balance = balance - v_total_cost
    WHERE "accountId" = v_user_account_id;

    -- 4. 거래 실행: 주식 지급
    IF v_my_current_qty IS NULL OR v_my_current_qty = 0 THEN
        INSERT INTO public.student_stocks ("userId", "stockId", quantity, "purchasePrice")
        VALUES (p_user_id, p_stock_id, p_quantity, v_stock_price);
    ELSE
        UPDATE public.student_stocks
        SET quantity = quantity + p_quantity,
            "purchasePrice" = (("purchasePrice" * v_my_current_qty) + v_total_cost) / (v_my_current_qty + p_quantity)
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    END IF;

    -- 5. 가격 변동 (매수 시 상승)
    -- 공식: 현재가 * (1 + (민감도 * 수량))
    -- (예: 민감도 1%일 때 1주 사면 1% 상승, 10주 사면 10% 상승)
    v_new_price := floor(v_stock_price * (1 + (coalesce(v_volatility, 0.01) * p_quantity)));

    UPDATE public.stock_products
    SET "currentPrice" = v_new_price
    WHERE id = p_stock_id;

    INSERT INTO public.stock_price_history ("stockId", price)
    VALUES (p_stock_id, v_new_price);

    -- 6. 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_user_account_id, 'StockBuy', -v_total_cost, '주식 매수: ' || p_quantity || '주');

    RETURN '매수되었습니다.';
END;
$function$;

-- 2. 매도 함수 (자가 증식 방지 수수료 적용)
CREATE OR REPLACE FUNCTION public.sell_stock(p_user_id text, p_stock_id text, p_quantity integer)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_stock_price numeric;
    v_volatility numeric;
    v_total_earn numeric;
    v_k numeric;        -- 민감도 k
    v_fee_rate numeric; -- 안전 수수료율 Fmin
    v_fee numeric;
    v_final_earn numeric;
    v_user_account_id text;
    v_current_qty integer;
    v_new_price numeric;
BEGIN
    -- 1. 보유 주식 확인
    SELECT quantity INTO v_current_qty
    FROM public.student_stocks
    WHERE "userId" = p_user_id AND "stockId" = p_stock_id;

    IF v_current_qty IS NULL OR v_current_qty < p_quantity THEN
        RAISE EXCEPTION '보유 주식이 부족합니다.';
    END IF;

    -- 2. 주식 정보 확인
    SELECT "currentPrice", volatility INTO v_stock_price, v_volatility
    FROM public.stock_products
    WHERE id = p_stock_id;

    -- 3. 수수료 및 정산금 계산 (자가 증식 방지 알고리즘)
    -- k = 민감도 (기본 0.01)
    v_k := coalesce(v_volatility, 0.01);

    -- 안전 수수료율 공식: Fmin = 10k / (2 + 10k)
    v_fee_rate := (10 * v_k) / (2 + (10 * v_k));

    v_total_earn := v_stock_price * p_quantity;
    v_fee := floor(v_total_earn * v_fee_rate);
    v_final_earn := v_total_earn - v_fee;

    -- 4. 계좌 확인
    SELECT "accountId" INTO v_user_account_id
    FROM public.accounts
    WHERE "userId" = p_user_id;

    -- 5. 거래 실행: 주식 차감
    IF v_current_qty = p_quantity THEN
        DELETE FROM public.student_stocks
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    ELSE
        UPDATE public.student_stocks
        SET quantity = quantity - p_quantity
        WHERE "userId" = p_user_id AND "stockId" = p_stock_id;
    END IF;

    -- 6. 거래 실행: 현금 입금 (수수료 제외 후 입금)
    UPDATE public.accounts
    SET balance = balance + v_final_earn
    WHERE "accountId" = v_user_account_id;

    -- 7. 가격 변동 (매도 시 하락)
    -- 공식: 현재가 * (1 - (민감도 * 수량))
    v_new_price := floor(v_stock_price * (1 - (v_k * p_quantity)));

    -- 가격이 1원 미만으로 떨어지지 않도록 방지
    IF v_new_price < 1 THEN v_new_price := 1; END IF;

    UPDATE public.stock_products
    SET "currentPrice" = v_new_price
    WHERE id = p_stock_id;

    INSERT INTO public.stock_price_history ("stockId", price)
    VALUES (p_stock_id, v_new_price);

    -- 8. 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_user_account_id, 'StockSell', v_final_earn, '주식 매도: ' || p_quantity || '주 (수수료 ' || v_fee || '권 차감)');

    RETURN '매도되었습니다. (수수료: ' || v_fee || '권)';
END;
$function$;
```

