    if (error) {
        console.warn("Could not fetch stock history:", error.message);
    } else {
        history = (data || []).map((item: any) => ({
            id: item.id,
            stockId: item.stockId || item.stockid, 
            price: item.price,
            createdAt: item.createdAt || item.createdat 
