payload.text:
네, 맞습니다. **Supabase의 SQL Editor**에서 쿼리를 실행하여 중복된 함수를 정리해야 문제가 해결됩니다.

현재 데이터베이스에 `cancel_savings`라는 이름의 함수가 두 개(하나는 ID를 문자로, 하나는 UUID로 받는 버전)가 있어서 시스템이 무엇을 써야 할지 몰라 **PGRST203 오류**가 발생하고 있습니다.

코드(`api.ts`)를 수정하지 않고 해결하려면, **데이터베이스에서 모호한 함수들을 삭제하고 명확한 하나의 함수로 다시 만들어야 합니다.**

아래 SQL을 복사하여 Supabase SQL Editor에서 실행해주세요.

```sql
-- 1. 기존 충돌나는 함수들 모두 삭제
DROP FUNCTION IF EXISTS public.cancel_savings(p_user_id text, p_saving_id uuid);
DROP FUNCTION IF EXISTS public.cancel_savings(p_user_id uuid, p_saving_id uuid);

-- 2. 명확한 하나의 함수로 재생성 (User ID를 text로 받음)
CREATE OR REPLACE FUNCTION public.cancel_savings(p_user_id text, p_saving_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_product_id uuid;
    v_amount numeric;
    v_rate numeric;
    v_cancellation_rate numeric;
    v_maturity_days integer;
    v_join_date timestamptz;
    v_days_elapsed integer;
    v_refund_amount numeric;
    v_user_account_id text;
BEGIN
    -- 1. 적금 정보 조회
    SELECT "productId", amount, "joinDate"
    INTO v_product_id, v_amount, v_join_date
    FROM public.student_savings
    WHERE "savingId" = p_saving_id AND "userId" = p_user_id;

    IF v_product_id IS NULL THEN
        RAISE EXCEPTION '해당 적금 정보를 찾을 수 없습니다.';
    END IF;

    -- 2. 상품 정보 조회 (해지 이율 확인)
    SELECT "cancellationRate"
    INTO v_cancellation_rate
    FROM public.savings_products
    WHERE id = v_product_id;

    -- 3. 환급액 계산 (원금 + 원금 * 해지이율)
    -- 해지 이율이 1(100%)이면 원금 보장 + @ 가 되므로, 보통 해지율은 0.x 대입니다.
    -- 만약 cancellationRate가 '패널티 비율'이 아니라 '적용 이율'이라면:
    v_refund_amount := floor(v_amount + (v_amount * v_cancellation_rate));

    -- 4. 적금 삭제
    DELETE FROM public.student_savings
    WHERE "savingId" = p_saving_id;

    -- 5. 계좌로 환급
    SELECT "accountId" INTO v_user_account_id
    FROM public.accounts
    WHERE "userId" = p_user_id;

    UPDATE public.accounts
    SET balance = balance + v_refund_amount
    WHERE "accountId" = v_user_account_id;

    -- 6. 거래 내역 기록
    INSERT INTO public.transactions ("accountId", type, amount, description)
    VALUES (v_user_account_id, 'SavingsCancel', v_refund_amount, '적금 중도 해지 환급');

    RETURN '적금이 해지되었습니다. (환급액: ' || v_refund_amount || '권)';
END;
$function$;

