제공해주신 정확한 테이블 정보 덕분에, 오류 없이 작동하는 완벽한 SQL 쿼리를 작성할 수 있습니다.
말씀해주신 컬럼명(대소문자 포함)을 정확히 반영하여 작성했습니다.

아래 SQL 코드를 **Supabase Dashboard > SQL Editor**에 복사해서 실행(Run)해주세요. 코드는 수정하지 않았습니다.

### Supabase SQL Editor 실행 쿼리

```sql
-- 기존 함수가 있다면 삭제하여 충돌 방지
DROP FUNCTION IF EXISTS public.cancel_student_savings(text, uuid);

-- 함수 생성: cancel_student_savings
-- 파라미터: p_user_id (text), p_saving_id (uuid)
CREATE OR REPLACE FUNCTION public.cancel_student_savings(p_user_id text, p_saving_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_product_id text;          -- savings_products.id가 text 타입임
    v_amount numeric;
    v_cancellation_rate numeric;
    v_refund_amount numeric;
    v_user_account_id text;
BEGIN
    -- 1. 적금 정보 조회 ("savingId", "userId", "productId" 등 대소문자 정확히 매칭)
    SELECT "productId", "amount"
    INTO v_product_id, v_amount
    FROM public.student_savings
    WHERE "savingId" = p_saving_id AND "userId" = p_user_id;

    IF v_product_id IS NULL THEN
        RAISE EXCEPTION '해당 적금 정보를 찾을 수 없습니다. (savingId: %, userId: %)', p_saving_id, p_user_id;
    END IF;

    -- 2. 상품 정보 조회 ("cancellationRate", "id" 매칭)
    SELECT "cancellationRate"
    INTO v_cancellation_rate
    FROM public.savings_products
    WHERE "id" = v_product_id;

    -- 3. 환급액 계산
    -- 원금 + (원금 * 해지이율). 해지이율이 0.01이면 1% 이자 지급, 음수면 차감.
    v_refund_amount := floor(v_amount + (v_amount * COALESCE(v_cancellation_rate, 0)));

    -- 4. 적금 데이터 삭제
    DELETE FROM public.student_savings
    WHERE "savingId" = p_saving_id;

    -- 5. 학생 계좌 ID 조회 (accounts 테이블 "accountId", "userId" 매칭)
    SELECT "accountId" INTO v_user_account_id
    FROM public.accounts
    WHERE "userId" = p_user_id;

    IF v_user_account_id IS NULL THEN
        RAISE EXCEPTION '학생 계좌를 찾을 수 없습니다.';
    END IF;

    -- 6. 계좌 잔액 업데이트 (환급) ("balance" 매칭)
    UPDATE public.accounts
    SET "balance" = "balance" + v_refund_amount
    WHERE "accountId" = v_user_account_id;

    -- 7. 거래 내역 기록 (transactions 테이블 컬럼명은 accounts와 유사하다고 가정)
    -- 만약 transactions 테이블 컬럼명이 다르다면 이 부분에서 에러가 날 수 있습니다.
    INSERT INTO public.transactions ("accountId", "type", "amount", "description", "date")
    VALUES (v_user_account_id, 'SavingsCancel', v_refund_amount, '적금 중도 해지 환급', now());

    RETURN '적금이 해지되었습니다. (환급액: ' || v_refund_amount || '권)';
END;
$function$;
```

